import React, { useState } from "react";
import Input from "./ui/Input";
import Button from "./ui/Button";

const BookAdd = () => {
  const [bookTitle, setBookTitle] = useState(""); // État pour stocker la valeur de l'input

  // Fonction pour gérer le changement dans l'input
  const handleInputChange = (event) => {
    setBookTitle(event.target.value); // Met à jour l'état avec la valeur de l'input
  };

  // Fonction pour envoyer les données au back-end
  const handleSubmit = () => {
    if (!bookTitle.trim()) {
      alert("Veuillez entrer un titre de livre.");
      return;
    }

    const bookToAdd = {
      title: bookTitle,
      description: "Description par défaut",
      page: 100, // Ajouter des pages par défaut
    };

    fetch("http://localhost:3000/api/book", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(bookToAdd),
    })
      .then((response) => {
        if (response.ok) {
          alert("Livre ajouté avec succès !");
          setBookTitle(""); // Réinitialise le champ d'entrée
        } else {
          throw new Error("Erreur lors de l'envoi des données.");
        }
      })
      .catch((error) => console.error("Erreur :", error));
  };

  return (
    <div className="w-[50vh] h-auto">
      <Input
        placeholder="Entrez le titre du livre"
        value={bookTitle} // Lie l'input à l'état
        onChange={handleInputChange} // Met à jour l'état
      />
      <Button onClick={handleSubmit}>Submit</Button>
    </div>
  );
};

export default BookAdd;
